import { 運筆 } from '../bi.js';
// ── 寶蓋：頂珠・穹蓋・沿板・垂幔四片・垂鈴二 ────────────────────────────────
export function 寶蓋(bi, x, z, 比 = 1, 淡 = 0.6) {
    const { M, L, C, Qk, S, 衣, 細, 逸 } = 運筆(bi);
    const g = (a, b) => [x + a * 比, z + b * 比];
    bi.dim(淡, () => {
        衣(() => {
            // 穹蓋雙緣
            M(...g(-7.2, 0));
            C(...g(-4.6, -3.4), ...g(4.6, -3.4), ...g(7.2, 0));
            S();
            M(...g(-7.2, 0.1));
            L(...g(7.2, 0.1));
            S();
            M(...g(-7.6, 1.3));
            L(...g(7.6, 1.3));
            S(); // 沿板
            // 頂珠與座
            M(...g(-1.1, -3.5));
            Qk(...g(0, -4.1), ...g(1.1, -3.5));
            S();
            bi.A(x, z - 5.0 * 比, 0.75 * 比);
            M(...g(-0.45, -5.6));
            Qk(...g(0, -6.3), ...g(0.45, -5.6));
            S(); // 珠焰
        });
        細(() => {
            // 垂幔四片（波腳）與垂鈴二
            for (const px of [-5.8, -2.0, 2.0, 5.8]) {
                M(...g(px - 1.15, 1.4));
                C(...g(px - 1.0, 3.0), ...g(px + 1.0, 3.0), ...g(px + 1.15, 1.4));
                S();
                逸(() => { M(...g(px - 0.55, 2.6)); Qk(...g(px, 3.35), ...g(px + 0.55, 2.6)); S(); });
            }
            for (const px of [-7.6, 7.6]) {
                M(...g(px, 1.4));
                L(...g(px, 2.6));
                S();
                bi.A(x + px * 比, z + 3.2 * 比, 0.55 * 比);
                bi.dot(x + px * 比, z + 3.95 * 比, 0.16 * 比);
            }
        });
    });
}
// ── 雙鹿法輪：八輻輪居中，左右鹿跪伏相向仰首 ────────────────────────────────
export function 雙鹿法輪(bi, x, z, 比 = 1, 淡 = 0.65) {
    const { M, C, Qk, S, 衣, 細 } = 運筆(bi);
    bi.dim(淡, () => {
        // 法輪：轂・輻八・輞雙環
        衣(() => { bi.A(x, z - 2.2 * 比, 2.5 * 比); });
        細(() => {
            bi.A(x, z - 2.2 * 比, 0.55 * 比);
            for (let k = 0; k < 8; k++) {
                const a = (k * Math.PI) / 4 + Math.PI / 8;
                M(x + Math.cos(a) * 0.62 * 比, z - 2.2 * 比 + Math.sin(a) * 0.62 * 比);
                Qk(x + Math.cos(a) * 1.5 * 比, z - 2.2 * 比 + Math.sin(a) * 1.5 * 比, x + Math.cos(a) * 2.35 * 比, z - 2.2 * 比 + Math.sin(a) * 2.35 * 比);
                S();
            }
            bi.A(x, z - 2.2 * 比, 2.05 * 比);
            // 輪頂寶珠
            M(x - 0.4 * 比, z - 4.85 * 比);
            Qk(x, z - 5.5 * 比, x + 0.4 * 比, z - 4.85 * 比);
            S();
        });
        // 二鹿（鏡像）：跪伏，背弧一線，仰首向輪，足收腹下，短尾
        for (const d of [-1, 1]) {
            const g = (a, b) => [x + d * a * 比, z + b * 比];
            衣(() => {
                // 軀之背弧：自臀過背至頸
                M(...g(7.4, -0.3));
                C(...g(6.6, -1.5), ...g(5.0, -1.9), ...g(3.9, -1.5));
                S();
                // 頸與首（仰向輪）
                M(...g(3.9, -1.5));
                C(...g(3.3, -2.4), ...g(3.05, -3.1), ...g(3.15, -3.7));
                S();
                M(...g(3.15, -3.7));
                Qk(...g(2.75, -4.05), ...g(2.6, -3.6));
                S(); // 吻
                M(...g(2.6, -3.6));
                Qk(...g(2.95, -2.9), ...g(3.5, -2.75));
                S(); // 頷線回頸
                // 腹線與跪足
                M(...g(7.15, 0.25));
                C(...g(6.0, 0.65), ...g(4.6, 0.7), ...g(3.6, 0.35));
                S();
                M(...g(3.6, 0.35));
                Qk(...g(3.35, -0.5), ...g(3.7, -1.1));
                S(); // 胸口收
            });
            細(() => {
                M(...g(5.6, 0.55));
                Qk(...g(5.1, 0.05), ...g(4.55, 0.5));
                S(); // 前跪足圈
                M(...g(6.9, 0.4));
                Qk(...g(6.5, -0.1), ...g(6.05, 0.4));
                S(); // 後足圈
                M(...g(7.4, -0.35));
                Qk(...g(7.8, -0.7), ...g(7.6, -1.1));
                S(); // 短尾
                M(...g(3.35, -4.0));
                Qk(...g(3.6, -4.6), ...g(3.95, -4.35));
                S(); // 耳（牝無角，簡一耳）
                bi.dot(x + d * 2.95 * 比, z - 3.62 * 比, 0.12 * 比); // 睛
            });
        }
    });
}
// ── 蓮池：水波三段・蓮葉二・開蓮一蕾一（淨土與唐卡座下之池）────────────────
export function 蓮池(bi, x, z, 半闊 = 16, 比 = 1, 淡 = 0.55) {
    const { M, C, Qk, S, 衣, 細, 逸 } = 運筆(bi);
    const w = 半闊 * 比;
    bi.dim(淡, () => {
        細(() => 逸(() => {
            // 水波三段（各三折）
            for (const [dz, k] of [[0, 1], [1.7, 0.85], [3.4, 0.7]]) {
                M(x - w * k, z + dz * 比);
                C(x - w * k * 0.5, z + (dz - 0.9) * 比, x - w * k * 0.15, z + (dz + 0.9) * 比, x, z + dz * 比);
                C(x + w * k * 0.15, z + (dz - 0.9) * 比, x + w * k * 0.5, z + (dz + 0.9) * 比, x + w * k, z + dz * 比);
                S();
            }
        }));
        衣(() => {
            // 蓮葉二（傘面橢圓＋葉臍）
            bi.E(x - w * 0.62, z - 1.2 * 比, 2.6 * 比, 1.05 * 比);
            bi.E(x + w * 0.58, z - 0.9 * 比, 2.2 * 比, 0.9 * 比);
            細(() => { bi.dot(x - w * 0.62, z - 1.2 * 比, 0.16 * 比); bi.dot(x + w * 0.58, z - 0.9 * 比, 0.14 * 比); });
            // 開蓮一（三瓣正面）
            const lx = x - w * 0.28, lz = z - 2.2 * 比;
            M(lx - 1.5 * 比, lz);
            Qk(lx, lz + 0.85 * 比, lx + 1.5 * 比, lz);
            S();
            M(lx - 1.5 * 比, lz);
            Qk(lx - 1.15 * 比, lz - 1.7 * 比, lx, lz - 1.95 * 比);
            S();
            M(lx + 1.5 * 比, lz);
            Qk(lx + 1.15 * 比, lz - 1.7 * 比, lx, lz - 1.95 * 比);
            S();
            細(() => { M(lx, lz - 1.9 * 比); Qk(lx + 0.1 * 比, lz - 0.9 * 比, lx, lz + 0.5 * 比); S(); });
            M(lx, lz + 0.8 * 比);
            Qk(lx - 0.2 * 比, lz + 1.9 * 比, lx, z + 0.2 * 比);
            S(); // 莖
            // 蓮蕾一（合掌形）
            const bx = x + w * 0.3, bz = z - 1.9 * 比;
            M(bx - 0.75 * 比, bz + 0.6 * 比);
            C(bx - 0.85 * 比, bz - 0.8 * 比, bx - 0.25 * 比, bz - 1.6 * 比, bx, bz - 1.7 * 比);
            S();
            M(bx + 0.75 * 比, bz + 0.6 * 比);
            C(bx + 0.85 * 比, bz - 0.8 * 比, bx + 0.25 * 比, bz - 1.6 * 比, bx, bz - 1.7 * 比);
            S();
            M(bx, bz + 0.9 * 比);
            Qk(bx + 0.15 * 比, bz + 1.8 * 比, bx, z + 0.1 * 比);
            S();
        });
    });
}
// ── 菩提樹：主幹雙緣・分枝三・心形葉七（犍陀羅觸地成道之景，樹冠覆頭光上）──
export function 菩提樹(bi, x, z, 比 = 1, 淡 = 0.55) {
    const { M, C, Qk, S, 衣, 細, 逸 } = 運筆(bi);
    const g = (a, b) => [x + a * 比, z + b * 比];
    const 葉 = (lx, lz, s, 傾 = 0) => {
        // 心形葉＋長尾尖（菩提葉之標誌）
        M(x + lx * 比, z + lz * 比);
        C(x + (lx - 1.3 * s) * 比, z + (lz - 1.1 * s) * 比, x + (lx - 1.5 * s + 傾) * 比, z + (lz + 0.9 * s) * 比, x + (lx + 傾 * 1.5) * 比, z + (lz + 2.1 * s) * 比);
        S();
        M(x + lx * 比, z + lz * 比);
        C(x + (lx + 1.3 * s) * 比, z + (lz - 1.1 * s) * 比, x + (lx + 1.5 * s + 傾) * 比, z + (lz + 0.9 * s) * 比, x + (lx + 傾 * 1.5) * 比, z + (lz + 2.1 * s) * 比);
        S();
    };
    bi.dim(淡, () => {
        衣(() => {
            // 主幹自畫外（構圖層置樹於尊後，幹沒於光後）：二段分枝
            M(...g(-6.5, 0));
            C(...g(-5.2, -2.8), ...g(-2.4, -4.6), ...g(0.6, -5.2));
            S();
            M(...g(6.8, -0.4));
            C(...g(5.4, -3.0), ...g(2.8, -4.8), ...g(0.6, -5.2));
            S();
            M(...g(-3.4, -2.2));
            Qk(...g(-2.2, -3.9), ...g(-0.6, -4.6));
            S();
            M(...g(3.8, -2.4));
            Qk(...g(2.4, -4.1), ...g(0.9, -4.7));
            S();
        });
        細(() => 逸(() => {
            葉(-5.6, -1.6, 0.85, -0.3);
            葉(-3.2, -3.6, 0.95, -0.15);
            葉(0.0, -4.9, 1.05, 0);
            葉(3.4, -3.5, 0.95, 0.15);
            葉(5.8, -1.5, 0.85, 0.3);
            葉(-1.7, -4.35, 0.8, -0.1);
            葉(1.9, -4.3, 0.8, 0.1);
        }));
    });
}
// ── 日月：日輪圓相・月輪偃月（藏地上界左右雙曜）────────────────────────────
export function 日月(bi, x日, x月, z, 比 = 1, 淡 = 0.55) {
    const { M, Qk, S, 衣, 細 } = 運筆(bi);
    bi.dim(淡, () => {
        衣(() => { bi.A(x日, z, 1.6 * 比); });
        細(() => { bi.A(x日, z, 1.15 * 比); });
        衣(() => {
            // 偃月：外弧全、內弧偏——月牙
            bi.A(x月, z, 1.55 * 比, Math.PI * 0.42, Math.PI * 1.98);
            M(x月 + Math.cos(Math.PI * 0.42) * 1.55 * 比, z + Math.sin(Math.PI * 0.42) * 1.55 * 比);
            Qk(x月 + 0.5 * 比, z - 0.15 * 比, x月 + Math.cos(Math.PI * 1.98) * 1.55 * 比, z + Math.sin(Math.PI * 1.98) * 1.55 * 比);
            S();
        });
    });
}
// ── 供水碗列：七碗一字排（藏地壇前之供）────────────────────────────────────
export function 供水碗列(bi, x, z, n = 7, 距 = 2.5, 比 = 1, 淡 = 0.55) {
    const { M, Qk, S, 細 } = 運筆(bi);
    bi.dim(淡, () => 細(() => {
        for (let k = 0; k < n; k++) {
            const px = x + (k - (n - 1) / 2) * 距 * 比;
            M(px - 1.0 * 比, z);
            Qk(px, z - 0.5 * 比, px + 1.0 * 比, z);
            S(); // 口沿
            M(px - 1.0 * 比, z);
            Qk(px - 0.75 * 比, z + 1.0 * 比, px, z + 1.05 * 比);
            S();
            M(px + 1.0 * 比, z);
            Qk(px + 0.75 * 比, z + 1.0 * 比, px, z + 1.05 * 比);
            S();
        }
    }));
}
// ═══ 邊帶三式：沿水平帶自 (x0,z) 至 (x1,z)，構圖層裁其長 ═══════════════════
// 連珠帶：珠列一行（犍陀羅框・尼瓦爾緣）
export function 連珠帶(bi, x0, x1, z, 徑 = 0.55, 淡 = 0.5) {
    if (!(徑 > 0) || !Number.isFinite(徑) || x0 === x1)
        return; // 守衛：徑非正／跨零則不畫
    bi.dim(淡, () => {
        const 步 = 徑 * 2.6;
        const n = Math.max(2, Math.floor(Math.abs(x1 - x0) / 步));
        const { 細 } = 運筆(bi);
        細(() => { for (let k = 0; k <= n; k++)
            bi.A(x0 + ((x1 - x0) * k) / n, z, 徑); });
    });
}
// 卷草帶：S 渦連綿（唐草——漢地東密框）
export function 卷草帶(bi, x0, x1, z, 高 = 1.6, 淡 = 0.5) {
    if (!(高 > 0) || !Number.isFinite(高) || x0 === x1)
        return;
    const { M, C, Qk, S, 細, 逸 } = 運筆(bi);
    bi.dim(淡, () => 細(() => 逸(() => {
        const 步 = 高 * 2.4;
        const n = Math.max(1, Math.floor(Math.abs(x1 - x0) / 步));
        const dir = x1 > x0 ? 1 : -1;
        for (let k = 0; k < n; k++) {
            const px = x0 + dir * k * 步;
            // 主蔓 S 一節
            M(px, z + 高 * 0.45);
            C(px + dir * 步 * 0.3, z - 高 * 0.75, px + dir * 步 * 0.62, z + 高 * 0.75, px + dir * 步, z - 高 * 0.45);
            S();
            // 卷鬚渦
            M(px + dir * 步 * 0.42, z + 高 * 0.1);
            Qk(px + dir * 步 * 0.28, z + 高 * 0.72, px + dir * 步 * 0.52, z + 高 * 0.62);
            S();
        }
    })));
}
// 火焰帶：焰舌相銜（尼瓦爾緣・忿怒光框）
export function 火焰帶(bi, x0, x1, z, 高 = 2.2, 淡 = 0.5) {
    if (!(高 > 0) || !Number.isFinite(高) || x0 === x1)
        return;
    const { M, C, S, 細 } = 運筆(bi);
    bi.dim(淡, () => 細(() => {
        const 步 = 高 * 1.15;
        const n = Math.max(1, Math.floor(Math.abs(x1 - x0) / 步));
        const dir = x1 > x0 ? 1 : -1;
        for (let k = 0; k < n; k++) {
            const px = x0 + dir * k * 步;
            M(px, z);
            C(px + dir * 步 * 0.55, z - 高 * 0.35, px + dir * 步 * 0.12, z - 高 * 0.7, px + dir * 步 * 0.62, z - 高);
            S();
            M(px + dir * 步 * 0.62, z - 高);
            C(px + dir * 步 * 0.95, z - 高 * 0.55, px + dir * 步 * 0.72, z - 高 * 0.25, px + dir * 步, z);
            S();
        }
    }));
}
// ── 欄楯：尋杖・盆唇・地栿三橫，望柱寶珠，櫺格斜十字（淨土變平臺之欄）──────
export function 欄楯(bi, x0, x1, z, 高 = 4.2, 柱距 = 4.5, 淡 = 0.6) {
    const { M, L, S, 衣, 細 } = 運筆(bi);
    bi.dim(淡, () => {
        衣(() => {
            M(x0, z - 高);
            L(x1, z - 高);
            S(); // 尋杖
            M(x0, z - 高 * 0.52);
            L(x1, z - 高 * 0.52);
            S(); // 盆唇
            M(x0, z);
            L(x1, z);
            S(); // 地栿
        });
        細(() => {
            const n = Math.max(1, Math.floor(Math.abs(x1 - x0) / 柱距));
            const dir = x1 > x0 ? 1 : -1;
            for (let k = 0; k <= n; k++) {
                const px = x0 + dir * k * 柱距;
                M(px, z);
                L(px, z - 高 - 0.6);
                S(); // 望柱
                bi.dot(px, z - 高 - 1.0, 0.28); // 柱頭珠
                if (k < n) { // 櫺格斜十字
                    const qx = px + dir * 柱距;
                    M(px, z - 高 * 0.52);
                    L(qx, z);
                    S();
                    M(qx, z - 高 * 0.52);
                    L(px, z);
                    S();
                }
            }
        });
    });
}
// ── 寶樹：雙緣主榦上分三枝，枝端雲頭葉冠，冠下垂瓔珞綴珠（淨土七寶行樹）────
export function 寶樹(bi, x, z, 高 = 22, 比 = 1, 淡 = 0.55) {
    const { M, L, C, Qk, S, 衣, 細, 逸 } = 運筆(bi);
    const h = 高 * 比;
    bi.dim(淡, () => {
        衣(() => {
            M(x - 0.9 * 比, z);
            C(x - 1.1 * 比, z - h * 0.4, x - 0.5 * 比, z - h * 0.62, x - 0.3 * 比, z - h * 0.72);
            S();
            M(x + 0.9 * 比, z);
            C(x + 1.1 * 比, z - h * 0.4, x + 0.5 * 比, z - h * 0.62, x + 0.3 * 比, z - h * 0.72);
            S();
            // 三枝
            M(x - 0.4 * 比, z - h * 0.68);
            Qk(x - 2.6 * 比, z - h * 0.78, x - 3.4 * 比, z - h * 0.86);
            S();
            M(x + 0.4 * 比, z - h * 0.68);
            Qk(x + 2.6 * 比, z - h * 0.78, x + 3.4 * 比, z - h * 0.86);
            S();
            M(x, z - h * 0.72);
            L(x, z - h * 0.9);
            S();
            // 雲頭葉冠三團（各三扇弧相接）
            for (const [cx, cz, r] of [[-3.6, 0.9, 2.5], [0, 0.98, 2.9], [3.6, 0.9, 2.5]]) {
                const gx = x + cx * 比, gz = z - h * cz, gr = r * 比;
                M(gx - gr, gz + gr * 0.35);
                C(gx - gr * 1.05, gz - gr * 0.5, gx - gr * 0.45, gz - gr * 0.95, gx, gz - gr * 0.72);
                S();
                M(gx, gz - gr * 0.72);
                C(gx + gr * 0.45, gz - gr * 0.95, gx + gr * 1.05, gz - gr * 0.5, gx + gr, gz + gr * 0.35);
                S();
                M(gx - gr, gz + gr * 0.35);
                Qk(gx, gz + gr * 0.62, gx + gr, gz + gr * 0.35);
                S();
            }
        });
        細(() => 逸(() => {
            // 冠下垂瓔珞二條綴珠
            for (const dx of [-2.2, 2.2]) {
                M(x + dx * 比, z - h * 0.82);
                Qk(x + dx * 0.7 * 比, z - h * 0.7, x + dx * 比, z - h * 0.58);
                S();
                bi.dot(x + dx * 0.82 * 比, z - h * 0.64, 0.2 * 比);
            }
            // 冠間摩尼珠（火焰三舌）
            bi.dot(x, z - h * 1.02, 0.42 * 比);
            M(x - 0.45 * 比, z - h * 1.02 - 0.3 * 比);
            Qk(x, z - h * 1.02 - 1.2 * 比, x + 0.45 * 比, z - h * 1.02 - 0.3 * 比);
            S();
        }));
    });
}
// ── 榜題牌：豎長方框，頂如意雲頭蓋，內留白（成堂尊格之標）────────────────
export function 榜題牌(bi, x, z, 寬 = 3, 高 = 9, 淡 = 0.6) {
    const { M, L, Qk, S, 細 } = 運筆(bi);
    bi.dim(淡, () => 細(() => {
        M(x - 寬 / 2, z);
        L(x + 寬 / 2, z);
        L(x + 寬 / 2, z + 高);
        L(x - 寬 / 2, z + 高);
        L(x - 寬 / 2, z);
        S();
        // 如意雲頭蓋：兩逆向螺弧相抵
        M(x - 寬 / 2 - 0.4, z);
        Qk(x - 寬 / 4, z - 1.3, x, z - 0.55);
        S();
        M(x + 寬 / 2 + 0.4, z);
        Qk(x + 寬 / 4, z - 1.3, x, z - 0.55);
        S();
    }));
}
// ── 山石：階梯輪廓疊層平頂（青綠山之簡體），皴帶短弧 ────────────────────────
export function 山石(bi, x, z, 比 = 1, 鏡 = 1, 淡 = 0.5) {
    const { M, L, C, Qk, S, 衣, 細 } = 運筆(bi);
    const g = (a, b) => [x + 鏡 * a * 比, z + b * 比];
    bi.dim(淡, () => {
        衣(() => {
            // 三層階梯：平頂緩弧＋垂直折落
            M(...g(0, 0));
            Qk(...g(2.4, -1.6), ...g(4.6, -1.4));
            S();
            M(...g(4.6, -1.4));
            L(...g(4.9, 1.2));
            S();
            M(...g(4.9, 1.2));
            Qk(...g(7.2, -0.2), ...g(9.4, 0.4));
            S();
            M(...g(9.4, 0.4));
            L(...g(9.8, 3.6));
            S();
            M(...g(9.8, 3.6));
            Qk(...g(12.0, 2.6), ...g(13.8, 3.4));
            S();
            // 峰頂圓渾（三指節並排）
            M(...g(0, 0));
            Qk(...g(-0.9, -2.8), ...g(1.0, -3.2));
            S();
            M(...g(1.0, -3.2));
            Qk(...g(2.6, -3.5), ...g(3.2, -2.2));
            S();
        });
        細(() => {
            for (const [ax, az] of [[2.2, -0.4], [6.4, 0.8], [11.0, 2.2]]) {
                M(...g(ax, az));
                Qk(...g(ax + 1.0, az + 0.5), ...g(ax + 2.0, az + 0.3));
                S();
            }
        });
    });
}
